#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>

/*
 * Raspberry Pi GPIO Control via sysfs
 * Compile: gcc -o gpio_control gpio_control.c
 * Run: sudo ./gpio_control 17 1 (to set GPIO17 high)
 */

#define GPIO_BASE_PATH "/sys/class/gpio/"
#define BUFFER_SIZE 64

/* Write a value to a GPIO sysfs file */
int gpio_write_file(const char *filename, const char *value) {
    int fd;
    int len;

    fd = open(filename, O_WRONLY);
    if (fd < 0) {
        perror("Failed to open GPIO file");
        return -1;
    }

    len = strlen(value);
    if (write(fd, value, len) != len) {
        perror("Failed to write to GPIO file");
        close(fd);
        return -1;
    }

    close(fd);
    return 0;
}

/* Read a value from a GPIO sysfs file */
int gpio_read_file(const char *filename, char *buffer, int size) {
    int fd;
    int bytes_read;

    fd = open(filename, O_RDONLY);
    if (fd < 0) {
        perror("Failed to open GPIO file");
        return -1;
    }

    bytes_read = read(fd, buffer, size - 1);
    if (bytes_read < 0) {
        perror("Failed to read from GPIO file");
        close(fd);
        return -1;
    }

    buffer[bytes_read] = '\0';
    close(fd);
    return bytes_read;
}

/* Export a GPIO pin for use */
int gpio_export(int pin) {
    char buffer[BUFFER_SIZE];
    char export_path[BUFFER_SIZE];

    snprintf(export_path, sizeof(export_path), "%sgpio%d", GPIO_BASE_PATH, pin);

    /* Check if already exported */
    if (access(export_path, F_OK) == 0) {
        printf("GPIO %d already exported\n", pin);
        return 0;
    }

    snprintf(buffer, sizeof(buffer), "%d", pin);
    return gpio_write_file(GPIO_BASE_PATH "export", buffer);
}

/* Unexport a GPIO pin */
int gpio_unexport(int pin) {
    char buffer[BUFFER_SIZE];

    snprintf(buffer, sizeof(buffer), "%d", pin);
    return gpio_write_file(GPIO_BASE_PATH "unexport", buffer);
}

/* Set GPIO pin direction (in, out, high, low) */
int gpio_set_direction(int pin, const char *direction) {
    char path[BUFFER_SIZE];

    snprintf(path, sizeof(path), "%sgpio%d/direction", GPIO_BASE_PATH, pin);
    return gpio_write_file(path, direction);
}

/* Set GPIO pin value (0 or 1) */
int gpio_set_value(int pin, int value) {
    char path[BUFFER_SIZE];
    char val_buffer[BUFFER_SIZE];

    snprintf(path, sizeof(path), "%sgpio%d/value", GPIO_BASE_PATH, pin);
    snprintf(val_buffer, sizeof(val_buffer), "%d", value);
    return gpio_write_file(path, val_buffer);
}

/* Get GPIO pin value */
int gpio_get_value(int pin) {
    char path[BUFFER_SIZE];
    char buffer[BUFFER_SIZE];

    snprintf(path, sizeof(path), "%sgpio%d/value", GPIO_BASE_PATH, pin);

    if (gpio_read_file(path, buffer, BUFFER_SIZE) < 0) {
        return -1;
    }

    return atoi(buffer);
}

/* Example: LED blink function */
void blink_led(int pin, int count, int delay_ms) {
    int i;

    printf("Blinking GPIO %d %d times\n", pin, count);

    for (i = 0; i < count; i++) {
        gpio_set_value(pin, 1);
        printf("  LED ON\n");
        usleep(delay_ms * 1000);

        gpio_set_value(pin, 0);
        printf("  LED OFF\n");
        usleep(delay_ms * 1000);
    }
}

/* Example: Read button state */
int read_button(int pin) {
    int value;

    value = gpio_get_value(pin);
    if (value < 0) {
        return -1;
    }

    return value;
}

int main(int argc, char *argv[]) {
    int pin;
    int value;

    /* Check for correct arguments */
    if (argc < 2) {
        printf("Usage: %s <gpio_pin> [value]\n", argv[0]);
        printf("Examples:\n");
        printf("  %s 17 1          # Set GPIO17 HIGH\n", argv[0]);
        printf("  %s 17 0          # Set GPIO17 LOW\n", argv[0]);
        printf("  %s 17             # Read GPIO17 value\n", argv[0]);
        return 1;
    }

    pin = atoi(argv[1]);

    /* Export GPIO pin */
    if (gpio_export(pin) != 0) {
        fprintf(stderr, "Failed to export GPIO %d\n", pin);
        return 1;
    }

    usleep(100000); /* Wait 100ms for export to complete */

    /* Set direction to output */
    if (gpio_set_direction(pin, "out") != 0) {
        fprintf(stderr, "Failed to set direction for GPIO %d\n", pin);
        return 1;
    }

    /* Check if setting value or reading */
    if (argc >= 3) {
        value = atoi(argv[2]);

        if (value != 0 && value != 1) {
            fprintf(stderr, "Invalid value. Use 0 or 1\n");
            gpio_unexport(pin);
            return 1;
        }

        /* Set GPIO value */
        if (gpio_set_value(pin, value) != 0) {
            fprintf(stderr, "Failed to set GPIO %d value\n", pin);
            gpio_unexport(pin);
            return 1;
        }

        printf("GPIO %d set to %d\n", pin, value);
    } else {
        /* Read GPIO value */
        value = gpio_get_value(pin);
        if (value < 0) {
            fprintf(stderr, "Failed to read GPIO %d value\n", pin);
            gpio_unexport(pin);
            return 1;
        }

        printf("GPIO %d value: %d\n", pin, value);
    }

    /* Example: Blink 5 times if value set */
    if (argc >= 3) {
        printf("\nRunning LED blink demonstration...\n");
        blink_led(pin, 5, 200);
    }

    /* Cleanup: unexport GPIO pin */
    gpio_unexport(pin);
    printf("GPIO %d unexported\n", pin);

    return 0;
}
